import { Hono } from "hono";
import { cors } from "hono/cors";
import { logger } from "hono/logger";
import { ChatService } from "./chains/chat-service";
import { RAGService } from "./rag/rag-service";
import { AgentOrchestrator } from "./agents/orchestrator";

const app = new Hono().basePath("/ai");

app.use("*", logger());
app.use("*", cors());

const chatService = new ChatService();
const ragService = new RAGService();
const agentOrchestrator = new AgentOrchestrator();

// Health check
app.get("/health", (c) => {
  return c.json({
    status: "ok",
    service: "ai-engine",
    timestamp: new Date().toISOString(),
  });
});

// ============ CHAT COMPLETION ============

// POST /ai/chat
app.post("/chat", async (c) => {
  const { message, conversationId, tenantId, agentId, context } = await c.req.json();

  const response = await chatService.generateResponse({
    message,
    conversationId,
    tenantId,
    agentId,
    context,
  });

  return c.json({ success: true, data: response });
});

// POST /ai/chat/stream (SSE)
app.post("/chat/stream", async (c) => {
  const { message, conversationId, tenantId, agentId } = await c.req.json();

  const stream = await chatService.generateStreamResponse({
    message,
    conversationId,
    tenantId,
    agentId,
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
});

// ============ RAG ============

// POST /ai/rag/query
app.post("/rag/query", async (c) => {
  const { query, knowledgeBaseId, topK } = await c.req.json();

  const results = await ragService.query(query, knowledgeBaseId, topK || 5);
  return c.json({ success: true, data: results });
});

// POST /ai/rag/ingest
app.post("/rag/ingest", async (c) => {
  const { documentId, content, knowledgeBaseId } = await c.req.json();

  await ragService.ingestDocument(documentId, content, knowledgeBaseId);
  return c.json({ success: true, message: "Document ingested" });
});

// ============ AGENTS ============

// POST /ai/agents/execute
app.post("/agents/execute", async (c) => {
  const { agentId, tenantId, input, tools } = await c.req.json();

  const result = await agentOrchestrator.execute({
    agentId,
    tenantId,
    input,
    tools,
  });

  return c.json({ success: true, data: result });
});

// ============ UTILITIES ============

// POST /ai/summarize
app.post("/summarize", async (c) => {
  const { text, maxLength } = await c.req.json();
  const summary = await chatService.summarize(text, maxLength);
  return c.json({ success: true, data: { summary } });
});

// POST /ai/sentiment
app.post("/sentiment", async (c) => {
  const { text } = await c.req.json();
  const sentiment = await chatService.analyzeSentiment(text);
  return c.json({ success: true, data: sentiment });
});

// POST /ai/translate
app.post("/translate", async (c) => {
  const { text, targetLanguage } = await c.req.json();
  const translated = await chatService.translate(text, targetLanguage);
  return c.json({ success: true, data: { translated } });
});

// Start server
const port = Number(process.env.AI_ENGINE_PORT) || 3381;
console.log(`🤖 AI Engine running on port ${port}`);

export default {
  port,
  fetch: app.fetch,
};

