  return c.json({
    status: "ok",
    service: "audira-api",
    timestamp: new Date().toISOString(),
  });
});

// Routes
app.route("/auth", authRoutes);
app.route("/users", usersRoutes);
app.route("/tenants", tenantsRoutes);
app.route("/contacts", contactsRoutes);
app.route("/conversations", conversationsRoutes);
app.route("/messages", messagesRoutes);
app.route("/campaigns", campaignsRoutes);
app.route("/crm", crmRoutes);
app.route("/analytics", analyticsRoutes);
app.route("/webhooks", webhooksRoutes);
app.route("/settings", settingsRoutes);
app.route("/notifications", notificationsRoutes);
app.route("/ai-agents", aiAgentsRoutes);
app.route("/knowledge-base", knowledgeBaseRoutes);
app.route("/workflows", workflowsRoutes);
app.route("/uploads", uploadsRoutes);
app.route("/telegram", telegramRoutes);
app.route("/discord", discordRoutes);
app.route("/canned-responses", cannedResponsesRoutes);
app.route("/scheduled-messages", scheduledMessagesRoutes);
app.route("/templates", templatesRoutes);
app.route("/segments", segmentsRoutes);
app.route("/csat", csatRoutes);
app.route("/email", emailRoutes);
app.route("/sla", slaRoutes);
app.route("/outgoing-webhooks", outgoingWebhooksRoutes);
app.route("/custom-fields", customFieldsRoutes);
app.route("/team", teamRoutes);
app.route("/chatbot-flows", chatbotFlowsRoutes);
app.route("/language", languageRoutes);
app.route("/security", securityRoutes);

// Public webhook endpoints (no auth)
app.route("/", telegramWebhookRoute);
app.route("/", discordWebhookRoute);
app.route("/", emailWebhookRoute);

// Error handler
app.onError(errorHandler);

// Not found
app.notFound((c) => {
  return c.json({ success: false, error: "Route not found" }, 404);
});

// Start server
const port = Number(process.env.PORT) || 3378;

logger.info(`🚀 Audira API running on port ${port}`);

const server = Bun.serve({
  port,
  fetch: app.fetch,
});

// Initialize Socket.IO
initSocketIO(server);

export default app;
